from __future__ import annotations

import argparse
import json
import os
import re
import subprocess
from datetime import datetime
from pathlib import Path

from runtime_state_schema import build_precheck_runtime_truth, get_runtime_truth

ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = ROOT / "research" / "reports"
WORKSPACE_ROOT = ROOT.parents[1] if len(ROOT.parents) >= 2 else ROOT
STATE_PATH = Path(
    str(
        os.environ.get("PREMARKET_PRECHECK_STATE_PATH")
        or (WORKSPACE_ROOT / "memory" / "premarket_precheck_state.json")
    )
)


def now_shanghai() -> datetime:
    return datetime.now()


def load_state() -> dict:
    if not STATE_PATH.exists():
        return {}
    try:
        return json.loads(STATE_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {}


def save_state(payload: dict) -> None:
    STATE_PATH.parent.mkdir(parents=True, exist_ok=True)
    STATE_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def is_trading_day(date_str: str) -> bool:
    """
    交易日判断：优先用腾讯行情 API，API 异常时降级为工作日（周一~五）判断。
    """
    try:
        date_obj = datetime.strptime(date_str, "%Y-%m-%d")
        weekday_fallback = date_obj.weekday() < 5
    except Exception:
        weekday_fallback = False

    if date_obj.weekday() >= 5:  # 周末直接返回 False
        return False

    try:
        import urllib.request
        req = urllib.request.Request(
            "https://qt.gtimg.cn/q=sh000001",
            headers={"User-Agent": "Mozilla/5.0"},
        )
        with urllib.request.urlopen(req, timeout=5) as resp:
            content = resp.read().decode("gbk", errors="replace")
        for line in content.split(";"):
            if "sh000001" in line:
                parts = line.split("~")
                if len(parts) > 30:
                    mkt_str = parts[30].strip()[:8]
                    market_date = f"{mkt_str[:4]}-{mkt_str[4:6]}-{mkt_str[6:8]}"
                    return market_date == date_str
                break
        return weekday_fallback
    except Exception:
        return weekday_fallback


def in_window(hhmm: str, start: str, end: str) -> bool:
    return start <= hhmm <= end


def _extract_yyyymmdd(name: str) -> str:
    m = re.search(r"(20\d{6})", name)
    return m.group(1) if m else ""


def latest_by_patterns(
    patterns: list[str],
    *,
    required_date_tag: str = "",
    allow_stale: bool = True,
) -> Path | None:
    if required_date_tag:
        for pat in patterns:
            dated = sorted(
                [p for p in REPORT_DIR.glob(pat) if _extract_yyyymmdd(p.name) == required_date_tag],
                key=lambda p: p.stat().st_mtime,
                reverse=True,
            )
            if dated:
                return dated[0]
        if not allow_stale:
            return None

    for pat in patterns:
        files = sorted(REPORT_DIR.glob(pat), key=lambda p: p.stat().st_mtime, reverse=True)
        if files:
            return files[0]
    return None


def build_empty_today_ticket(date_tag: str) -> tuple[Path, dict]:
    """构造当日空票据，避免因“无当日票据文件”导致流程中断。"""
    fallback = latest_by_patterns(
        [
            "stock_signal_tickets_live_*.csv",
            "stock_signal_tickets_*.csv",
            "live_stock_signal_*.csv",
            "stock_orders_signal_*.csv",
            "joinquant_order_tickets_*.csv",
        ],
        allow_stale=True,
    )

    default_header = "ticket_time,ts_code,side,source_time,source_qty,source_price,source_amount,reason,confirm_status,execute_status,notes"
    header = default_header
    if fallback and fallback.exists():
        try:
            first_line = fallback.read_text(encoding="utf-8").splitlines()[0].strip()
            if first_line:
                header = first_line
        except Exception:
            pass

    out = REPORT_DIR / f"joinquant_order_tickets_{date_tag}_autogen.csv"
    out.write_text(header + "\n", encoding="utf-8")
    return out, {
        "autogen": True,
        "autogen_reason": "no_today_tickets_use_empty_template",
        "autogen_from": str(fallback) if fallback else "",
    }


def prepare_today_ticket(date_tag: str, available_cash: float, account_nav: float) -> tuple[Path | None, dict]:
    cmd = [
        "python3",
        "scripts/prepare_live_signal_tickets.py",
        "--date",
        date_tag,
        "--available-cash",
        str(available_cash),
        "--account-nav",
        str(account_nav),
    ]
    proc = subprocess.run(cmd, cwd=str(ROOT), capture_output=True, text=True)

    meta: dict = {
        "prepared": proc.returncode == 0,
        "cmd": " ".join(cmd),
        "returncode": proc.returncode,
        "stdout": proc.stdout,
        "stderr": proc.stderr,
    }
    stdout = (proc.stdout or "").strip()
    if stdout:
        try:
            parsed = json.loads(stdout)
            if isinstance(parsed, dict):
                meta.update(parsed)
        except Exception:
            pass

    ticket_file = str(meta.get("ticket_file") or "").strip()
    ticket_path = Path(ticket_file).resolve() if ticket_file else None
    if ticket_path is not None and ticket_path.exists():
        meta["autogen"] = bool(meta.get("status") == "EMPTY")
        meta["autogen_reason"] = str(meta.get("reason") or "")
        return ticket_path, meta
    return None, meta


def run_precheck(available_cash: float, account_nav: float, tickets: Path, holdings: Path | None) -> dict:
    cmd = [
        "python3",
        "scripts/run_live_execution_v1.py",
        "--trading-mode",
        "live",
        "--allow-advice-only",
        "--config",
        "config/live_stock_alpha_v3.json",
        "--available-cash",
        str(available_cash),
        "--account-nav",
        str(account_nav),
        "--tickets",
        str(tickets),
    ]
    if holdings is not None:
        cmd.extend(["--holdings", str(holdings)])

    proc = subprocess.run(cmd, cwd=str(ROOT), capture_output=True, text=True)

    parsed = {}
    stdout = (proc.stdout or "").strip()
    if stdout:
        try:
            parsed = json.loads(stdout)
        except Exception:
            parsed = {"raw_stdout": stdout}

    return {
        "cmd": " ".join(cmd),
        "returncode": proc.returncode,
        "stdout": proc.stdout,
        "stderr": proc.stderr,
        "parsed": parsed,
    }


def build_execution_truth(result: dict, ticket_meta: dict | None = None) -> dict:
    raw_returncode = result.get("returncode", 1)
    if raw_returncode is None:
        raw_returncode = 1
    raw_returncode = int(raw_returncode)

    parsed = result.get("parsed")
    if not isinstance(parsed, dict):
        return build_precheck_runtime_truth(
            mode="normal" if raw_returncode == 0 else "review_required",
            risk_off=False,
            hard_stop=False,
            halt_new_buy=False,
            source="auto_run_premarket_precheck",
            precheck_passed=raw_returncode == 0,
            pipeline_ok=raw_returncode == 0,
        )

    embedded_truth = get_runtime_truth(parsed)
    if embedded_truth.get("trading_status"):
        if isinstance(ticket_meta, dict) and embedded_truth.get("state") == "no_signal":
            empty_signal_reason = str(ticket_meta.get("reason") or ticket_meta.get("autogen_reason") or "").strip()
            if empty_signal_reason:
                embedded_truth["trading_status_reason"] = empty_signal_reason
                embedded_truth["state_reason"] = empty_signal_reason
        return embedded_truth

    precheck = parsed.get("precheck") or {}
    reasons = [str(x).strip() for x in (precheck.get("reasons") or []) if str(x).strip()]
    halt_reason = str(parsed.get("halt_reason") or "").strip()
    hard_stop = bool(parsed.get("hard_stop"))
    risk_off = bool(parsed.get("risk_off"))
    halt_new_buy = bool(parsed.get("halt_new_buy"))
    mode = str(parsed.get("mode") or "").strip()
    precheck_passed = bool(precheck.get("passed"))

    no_order_reasons = {
        "预处理后无有效信号（pending_after_gate=0）",
        "净额合并后无有效订单（pending_netted=0）",
    }
    only_no_order_reasons = bool(reasons) and all(reason in no_order_reasons for reason in reasons)

    empty_signal_reason = ""

