#!/usr/bin/env python3
from __future__ import annotations

import argparse
import csv
import json
import os
import tempfile
from datetime import datetime
from pathlib import Path
from typing import Any


ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = ROOT / "research" / "reports"
PAPER_PROFILES = ["defensive", "balanced", "aggressive"]


def atomic_write_text(path: Path, content: str, *, encoding: str = "utf-8") -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with tempfile.NamedTemporaryFile("w", encoding=encoding, dir=str(path.parent), delete=False) as handle:
        handle.write(content)
        tmp_path = Path(handle.name)
    os.replace(tmp_path, path)


def atomic_write_json(path: Path, payload: Any) -> None:
    atomic_write_text(path, json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def load_json(path: Path | None) -> dict[str, Any]:
    if path is None or not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def load_csv_rows(path: Path | None) -> list[dict[str, str]]:
    if path is None or not path.exists():
        return []
    with path.open("r", encoding="utf-8-sig", newline="") as handle:
        return list(csv.DictReader(handle))


# 全局股票名称缓存（按ts_code索引）
_STOCK_NAME_MAP: dict[str, str] = {}


def _ensure_stock_name_map() -> None:
    """延迟加载股票名称映射表，只在首次需要时加载一次。"""
    global _STOCK_NAME_MAP
    if _STOCK_NAME_MAP:
        return
    list_path = ROOT / "data" / "tushare_a_all" / "a_stock_list.csv"
    if not list_path.exists():
        return
    for row in load_csv_rows(list_path):
        ts_code = str(row.get("ts_code") or "").strip()
        name = str(row.get("name") or "").strip()
        if ts_code and name:
            _STOCK_NAME_MAP[ts_code] = name


def enrich_rows_with_names(rows: list[dict[str, str]]) -> list[dict[str, str]]:
    """为每行补充 ai_stock_name（若该字段为空，则从股票名称表查询）。"""
    _ensure_stock_name_map()
    for row in rows:
        if not str(row.get("ai_stock_name") or "").strip():
            ts_code = str(row.get("ts_code") or "").strip()
            row["ai_stock_name"] = _STOCK_NAME_MAP.get(ts_code, "")
    return rows


def latest_file(pattern: str) -> Path | None:
    files = sorted(REPORT_DIR.glob(pattern))
    return files[-1] if files else None


def resolve_date_tag(explicit_date_tag: str | None) -> str:
    if explicit_date_tag:
        return explicit_date_tag

    tags: list[str] = []

    metrics_path = latest_file("paper_profiles_comparison_metrics_*.json")
    metrics = load_json(metrics_path)
    if metrics.get("date_tag"):
        tags.append(str(metrics["date_tag"]))

    account_candidates = sorted(REPORT_DIR.glob("paper_*_account_v1_latest.json"))
    for path in account_candidates:
        payload = load_json(path)
        if payload.get("date_tag"):
            tags.append(str(payload["date_tag"]))

    latest_live_system = latest_file("live_system_v1_*.json")
    if latest_live_system:
        tags.append(latest_live_system.stem.rsplit("_", 1)[-1])

    merged_dir = ROOT / "signals" / "merged"
    merged_candidates = sorted(merged_dir.glob("merged_signals_*.csv"))
    if merged_candidates:
        tags.append(merged_candidates[-1].stem.rsplit("_", 1)[-1])

    valid_tags = [tag for tag in tags if tag.isdigit() and len(tag) == 8]
    if valid_tags:
        return max(valid_tags)
    return datetime.now().strftime("%Y%m%d")


def latest_or_exact(pattern_prefix: str, date_tag: str, suffix: str) -> Path | None:
    exact = REPORT_DIR / f"{pattern_prefix}_{date_tag}.{suffix}"
    if exact.exists():
        return exact
    candidates = sorted(REPORT_DIR.glob(f"{pattern_prefix}_*.{suffix}"))
    if not candidates:
        return None
    eligible = [path for path in candidates if path.stem.rsplit("_", 1)[-1] <= date_tag]
    return eligible[-1] if eligible else candidates[-1]


def path_date_tag(path: Path | None) -> str:
    if path is None:
        return ""
    stem = path.stem
    tail = stem.rsplit("_", 1)[-1]
    return tail if len(tail) == 8 and tail.isdigit() else ""


def governance_gate_status(date_tag: str) -> dict[str, Any]:
    path = latest_or_exact("strategy_governance_gate", date_tag, "json") or (REPORT_DIR / "strategy_governance_gate_latest.json")
    payload = load_json(path if path and path.exists() else None)
    if not payload:
        return {
            "report_status": "MISSING",
            "blocking": True,
            "issues": ["missing_governance_gate_report"],
            "path": str(path) if path else "",
            "generated_at": "",
        }
    report_status = str(payload.get("overall_status") or "UNKNOWN").upper()
    issues = [str(item).strip() for item in (payload.get("blocking_issues") or []) if str(item).strip()]
    manual_review = payload.get("manual_review") or {}
    manual_review_decisions = [
        f"{str(item.get('strategy_id') or '').strip()}:{str(item.get('suggested_action') or '').strip()}"
        for item in (manual_review.get("decisions") or [])
        if str(item.get("strategy_id") or "").strip()
    ]
    return {
        "report_status": report_status,
        "blocking": report_status != "PASS" or bool(issues),
        "issues": issues,
        "path": str(path) if path else "",
        "generated_at": str(payload.get("generated_at") or ""),
        "manual_review_available": bool(manual_review.get("available")),
        "manual_review_signoff_pending": bool(manual_review.get("signoff_pending")),
        "manual_review_decisions": manual_review_decisions,
        "manual_review_path": str(manual_review.get("source_json") or ""),
    }


def to_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(str(value).replace(",", "").strip())
    except Exception:
        return default


def to_bool(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    return str(value).strip().lower() in {"1", "true", "yes", "y"}


def unique_ordered(items: list[str]) -> list[str]:
    return list(dict.fromkeys(item for item in items if item))


def parse_counter_map(value: Any) -> dict[str, int]:
    if isinstance(value, dict):
        return {
            str(k): int(to_float(v))
            for k, v in value.items()
            if str(k).strip()
        }
    text = str(value or "").strip()
    if not text:
        return {}
    try:
        parsed = json.loads(text)
    except Exception:
        return {}
    if not isinstance(parsed, dict):
        return {}
    return {
        str(k): int(to_float(v))
        for k, v in parsed.items()
        if str(k).strip()
    }


def fmt_pct(value: Any, digits: int = 2) -> str:
    if value in (None, ""):
        return "-"
    return f"{to_float(value):.{digits}f}"


def fmt_ratio_pct(value: Any, digits: int = 2) -> str:
    if value in (None, ""):
        return "-"
    return f"{to_float(value) * 100.0:.{digits}f}"


def format_realtime_meta(row: dict[str, Any]) -> str:
    source = str(row.get("ai_realtime_source") or "-").strip() or "-"
    confirmed_raw = str(row.get("ai_realtime_confirmed") or "").strip().lower()
    freshness = "FRESH" if confirmed_raw in {"1", "true", "yes", "y"} else "UNCERTAIN"
    return f"{source}/{freshness}"


def profile_payload(profile_slug: str, date_tag: str) -> dict[str, Any]:
    order_plan_candidate = REPORT_DIR / f"paper_{profile_slug}_order_plan_v1_{date_tag}.json"
    merged_orders_candidate = REPORT_DIR / f"paper_{profile_slug}_merged_proposed_orders_{date_tag}.csv"
    order_plan_path = order_plan_candidate if order_plan_candidate.exists() else None
    merged_orders_path = merged_orders_candidate if merged_orders_candidate.exists() else None
    order_plan = load_json(order_plan_path)
    return {
        "profile_slug": profile_slug,
        "order_plan_path": order_plan_path,
        "merged_orders_path": merged_orders_path,
        "order_plan": order_plan,
        "stats": order_plan.get("stats", {}) or {},
        "orders": load_csv_rows(merged_orders_path),
    }


def extract_runtime_snapshot_from_precheck(precheck: dict[str, Any]) -> dict[str, Any]:
    parsed = (((precheck or {}).get("result") or {}).get("parsed") or {})
    stats = (parsed.get("stats") or {}) if isinstance(parsed, dict) else {}

    gate_reasons = parsed.get("gate_reasons")
    if isinstance(gate_reasons, str):
        gate_reasons = [bit.strip() for bit in gate_reasons.split("|") if bit.strip()]
    elif not isinstance(gate_reasons, list):
        gate_reasons = []

    if not gate_reasons and isinstance(stats.get("gate_reasons"), str):
        gate_reasons = [bit.strip() for bit in str(stats.get("gate_reasons") or "").split("|") if bit.strip()]

    return {
        "mode": parsed.get("mode") or stats.get("mode"),
