def find_position(path: Path, code: str) -> dict[str, str]:
    rows = load_csv_rows(path)
    for row in rows:
        symbol = normalize_code(row.get("symbol") or row.get("ts_code") or "")
        if symbol == code:
            return row
    return {}


def find_live_order(date_tag: str, code: str) -> dict[str, str]:
    path = REPORT_DIR / f"live_orders_v1_{date_tag}.csv"
    for row in load_csv_rows(path):
        if normalize_code(row.get("ts_code") or "") == code:
            return row
    return {}


def find_today_report_entry(report: dict[str, Any], code: str) -> dict[str, Any]:
    for key in ["priority_candidates", "guarded_candidates", "display_tech_candidates", "display_guard_candidates", "sell_candidates_list"]:
        items = report.get(key) or []
        if isinstance(items, list):
            for item in items:
                if normalize_code(item.get("ts_code", "")) == code:
                    found = dict(item)
                    found["bucket"] = key
                    return found
    return {}


def collect_stock_view(code: str) -> dict[str, Any]:
    live_overlay = latest_path("live_stock_analysis_overlay_*.json")
    live_item = find_overlay_item(live_overlay, code)
    live_date_tag = (live_item.get("date_tag") if live_item else "") or datetime.now().strftime("%Y%m%d")

    profiles: list[dict[str, Any]] = []
    for profile in PROFILES:
        overlay_path = latest_path(f"paper_{profile}_stock_analysis_overlay_*.json")
        item = find_overlay_item(overlay_path, code)
        pos = find_position(REPORT_DIR / f"paper_{profile}_portfolio_positions_latest.csv", code)
        profiles.append(
            {
                "profile": profile,
                "overlay": item,
                "position": pos,
                "overlay_path": str(overlay_path) if overlay_path else "",
            }
        )

    selected_real_path = REPORT_DIR / f"selected_real_positions_{live_date_tag}_enriched.csv"
    if not selected_real_path.exists():
        selected_real_path = REPORT_DIR / f"selected_real_positions_{live_date_tag}.csv"
    if not selected_real_path.exists():
        selected_real_path = REPORT_DIR / f"account_holdings_selected_{live_date_tag}.csv"
    if not selected_real_path.exists():
        selected_real_path = REPORT_DIR / "account_holdings_selected_latest.csv"
    real_position = find_position(selected_real_path, code)
    live_order = find_live_order(live_date_tag, code)
    today_report = load_json(REPORT_DIR / f"today_stock_strategy_report_{live_date_tag}.json")
    today_entry = find_today_report_entry(today_report, code)

    name = (
        live_item.get("stock_name")
        or today_entry.get("ai_stock_name")
        or next((p["overlay"].get("stock_name") for p in profiles if p["overlay"].get("stock_name")), "")
    )
    position_profiles = [p for p in profiles if p["position"]]
    overlay_profiles = [p for p in profiles if p["overlay"]]

    instant_analysis = run_instant_analysis(code)
    volume_structure = calc_volume_structure(code)
    technical_indicators = calc_technical_indicators(code)
    holder_data = calc_holder_data(code)
    fundamental_data = calc_fundamental_data(code)

    summary = {
        "ts_code": code,
        "jq_code": normalize_jq(code),
        "stock_name": name,
        "has_live_overlay": bool(live_item),
        "has_paper_overlay": bool(overlay_profiles),
        "in_positions": [p["profile"] for p in position_profiles],
        "profiles_with_overlay": [p["profile"] for p in overlay_profiles],
        "in_real_holdings": bool(real_position),
        "in_live_orders": bool(live_order),
        "in_today_report": bool(today_entry),
        "live_date_tag": live_date_tag,
    }
    return {
        "summary": summary,
        "instant_analysis": instant_analysis,
        "technical_indicators": technical_indicators,
        "holder_data": holder_data,
        "fundamental_data": fundamental_data,
        "volume_structure": volume_structure,
        "live": live_item,
        "live_order": live_order,
        "today_report_meta": {
            "risk_mode": today_report.get("risk_mode"),
            "hard_stop": today_report.get("hard_stop"),
            "halt_new_buy": today_report.get("halt_new_buy"),
            "trigger_reason": today_report.get("trigger_reason"),
            "gate_reasons": today_report.get("gate_reasons") or [],
            "date_tag": today_report.get("date_tag") or live_date_tag,
        },
        "today_report_entry": today_entry,
        "real_position": real_position,
        "profiles": profiles,
        "generated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
    }


def fmt(v: Any) -> str:
    return "-" if v in (None, "") else str(v)


def render_md(view: dict[str, Any]) -> str:
    s = view["summary"]
    live = view.get("live") or {}
    instant_analysis = view.get("instant_analysis") or {}
    technical_indicators = view.get("technical_indicators") or {}
    live_order = view.get("live_order") or {}
    real_position = view.get("real_position") or {}
    report_meta = view.get("today_report_meta") or {}
    report_entry = view.get("today_report_entry") or {}

    lines: list[str] = []
    lines.append(f"# 个股透镜｜{s['ts_code']} {s.get('stock_name') or ''}".rstrip())
